class Solution:
    def sumOfBeauties(self, nums):
        n = len(nums)
        total = 0
        for i in range(1, n - 1):
            left_ok = all(nums[j] < nums[i] for j in range(0, i))
            right_ok = all(nums[i] < nums[k] for k in range(i + 1, n))
            if left_ok and right_ok:
                total += 2
            elif nums[i - 1] < nums[i] < nums[i + 1]:
                total += 1
        return total

